PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
SELECT ?goals
WHERE {
  wd:Q12897 p:P54 ?membership .
  ?membership ps:P54 wd:Q646135 ;
             pq:P1114 ?goals ;
             pq:P7546 "1976" .
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?goals
WHERE {
  wd:Q12897 p:P54 ?statement .
  ?statement ps:P54 wd:Q646135 ;
             pq:P1351 ?goals ;
             pq:P7546 ?season .
  FILTER (?season = "1976")
}
LIMIT 10
